import React, { useState, useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";
import { createDeliveryBoy, resetState } from "../features/delivery/deliveryBoySlice";
import { useNavigate } from "react-router-dom";
import { Button, Select } from "antd";
import {
  Truck,
  Save,
  ArrowLeft,
  ChevronRight,
  User,
  Mail,
  Phone,
  Lock,
  ShieldCheck,
  UserPlus,
} from "lucide-react";

const CreateDeliveryBoy = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { isLoading, isSuccess, isError, message } = useSelector(
    (state) => state.deliveryBoy,
  );

  const [formData, setFormData] = useState({
    firstname: "",
    lastname: "",
    email: "",
    mobile: "",
    password: "",
    role: "deliveryBoy",
  });

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    dispatch(createDeliveryBoy(formData));
  };

  useEffect(() => {
    if (isSuccess) {
      setFormData({
        firstname: "",
        lastname: "",
        email: "",
        mobile: "",
        password: "",
        role: "deliveryBoy",
      });
      dispatch(resetState()); // Add this
      navigate("/admin/delivery-boy-list");
    }
    if (isError) {
      console.error(message);
    }
  }, [isSuccess, isError, message, navigate]);

  const fields = [
    {
      name: "firstname",
      label: "First Name",
      type: "text",
      icon: <User size={18} />,
      placeholder: "Enter first name",
    },
    {
      name: "lastname",
      label: "Last Name",
      type: "text",
      icon: <User size={18} />,
      placeholder: "Enter last name",
    },
    {
      name: "email",
      label: "Email Address",
      type: "email",
      icon: <Mail size={18} />,
      placeholder: "agent@ethiopharmacy.com",
    },
    {
      name: "mobile",
      label: "Mobile Number",
      type: "text",
      icon: <Phone size={18} />,
      placeholder: "+251 9XX XXX XXX",
    },
    {
      name: "password",
      label: "Password",
      type: "password",
      icon: <Lock size={18} />,
      placeholder: "Create secure password",
    },
  ];

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-1000">
      {/* Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 bg-white/40 p-1 rounded-[32px] border border-white/60">
        <div className="pl-8 py-6">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-10 h-10 bg-[#257CB7] rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-500/20">
              <UserPlus size={20} />
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tighter">
              Register Field Agent
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <span className="flex items-center gap-2 text-[10px] font-black text-blue-600 bg-blue-50 border border-blue-100 px-3 py-1 rounded-full uppercase tracking-widest shadow-sm">
              <Truck size={12} /> Logistics Management
            </span>
          </div>
        </div>
        <div className="flex items-center gap-3 pr-4">
          <Button
            onClick={() => navigate(-1)}
            icon={<ArrowLeft size={16} />}
            className="rounded-2xl h-11 border-slate-200 text-slate-400 font-black text-[10px] uppercase tracking-widest"
          >
            Go Back
          </Button>
        </div>
      </div>

      {/* Form Card */}
      <div className="max-w-2xl">
        <div className="enterprise-card bg-white p-2 border-none shadow-2xl shadow-slate-200/40">
          <div className="flex items-center gap-4 px-10 py-8 border-b border-slate-50">
            <div className="p-3 bg-slate-50 rounded-2xl border border-slate-100">
              <Truck size={22} className="text-slate-400" />
            </div>
            <div>
              <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">
                Agent Profile
              </h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">
                Delivery personnel registration
              </p>
            </div>
          </div>
          <form onSubmit={handleSubmit} className="p-10 space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {fields.map((field) => (
                <div
                  key={field.name}
                  className={`space-y-3 ${field.name === "email" ? "md:col-span-2" : ""}`}
                >
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest flex items-center gap-2">
                    <ChevronRight size={12} /> {field.label}
                  </label>
                  <div className="relative">
                    <div className="absolute top-1/2 left-4 -translate-y-1/2 text-slate-300">
                      {field.icon}
                    </div>
                    <input
                      type={field.type}
                      name={field.name}
                      placeholder={field.placeholder}
                      value={formData[field.name]}
                      onChange={handleChange}
                      required
                      className="w-full pl-12 pr-6 py-4 bg-slate-50/50 border border-slate-100 rounded-2xl focus:outline-none focus:ring-2 focus:ring-[#257CB7] focus:border-transparent transition-all duration-300 font-bold text-slate-900 placeholder-slate-300"
                    />
                  </div>
                </div>
              ))}
            </div>

            <div className="space-y-3">
              <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest flex items-center gap-2">
                <ChevronRight size={12} /> Role Assignment
              </label>
              <Select
                value={formData.role}
                onChange={(value) => setFormData({ ...formData, role: value })}
                className="w-full h-14"
              >
                <Select.Option value="deliveryBoy">
                  Delivery Agent
                </Select.Option>
              </Select>
            </div>

            <Button
              type="primary"
              htmlType="submit"
              loading={isLoading}
              size="large"
              icon={<Save size={16} />}
              className="bg-[#257CB7] rounded-2xl h-14 font-black text-[10px] uppercase tracking-widest shadow-xl shadow-blue-500/20 border-none hover:translate-y-[-2px] transition-all w-full flex items-center justify-center gap-3 mt-4"
            >
              Register Field Agent
            </Button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default CreateDeliveryBoy;
